#include<bits/stdc++.h>
using namespace std;

const int N = 1e4 + 5;

int dfn[N], vis[N], low[N], s[N], dfncnt, scc[N], tp, sc, a[N], a_new[N], in[N], dp[N];

vector<int> e1[N], e2[N];

void tarjan(int u) {
    low[u] = dfn[u] = ++dfncnt, s[++tp] = u, vis[u] = 1;
    for (int v : e1[u]) {
        if (!dfn[v]) {
            tarjan(v);
            low[u] = min(low[u], low[v]);
        } 
        else if (vis[v]) {
            low[u] = min(low[u], dfn[v]);
        }
    }
    if (dfn[u] == low[u]) {
        ++sc;
        do {
            scc[s[tp]] = sc;
            a_new[sc] += a[s[tp]];
            vis[s[tp]] = 0;
        }
        while (s[tp--] != u);
    }
}

void toposort()
{
    queue<int> q;
    for(int i = 1; i <= sc; i++)
        if(!in[i])
        {
            q.push(i);
            dp[i] = a_new[i];
        }
    while(!q.empty())
    {
        int u = q.front();q.pop();
        for(int v : e2[u])
        {
            dp[v] = max(dp[v], dp[u] + a_new[v]);
            --in[v];
            if(!in[v]) q.push(v);
        }
    }
}

int main() {
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    for(int i = 1; i <= m; i++) {
        int u, v;
        cin >> u >> v;
        e1[u].push_back(v);
    }
    for(int i = 1; i <= n; i++) {
        if(!dfn[i]) {
            tarjan(i);
        }
    }
    for(int u = 1; u <= n; u++)
        for(int v : e1[u])
        {
            if(scc[u] != scc[v])
            {
                e2[scc[u]].push_back(scc[v]);
                in[scc[v]]++;
            }
        }
    toposort();
    int ans = 0;
    for(int i = 1; i <= sc; i++)
        ans = max(ans, dp[i]);
    cout << ans;

    return 0;
}
